def post_select_particle_number(bitstrings, counts, target_n):
    """
    Post-select on particle number (number of 1s in bitstring).
    """
    filtered = {}

    for bs, count in zip(bitstrings, counts):
        # Count number of 1s in bitstring
        n_particles = bs.count('1')

        # Keep only if matches target
        if n_particles == target_n:
            filtered[bs] = count

    return filtered
